import java.io.*;import java.util.*;class Main{static boolean feasible(int[] nums,int k,double mid){double total=0,prev=0,minPrev=0;for(int i=0;i<nums.length;i++){total+=nums[i]-mid;if(i>=k){prev+=nums[i-k]-mid;if(prev<minPrev)minPrev=prev;}if(i+1>=k&&total-minPrev>=0)return true;}return false;}static double solve(int[] nums,int k){double lo=nums[0],hi=nums[0];for(int x:nums){if(x<lo)lo=x;if(x>hi)hi=x;}for(int i=0;i<60;i++){double mid=(lo+hi)/2.0;if(feasible(nums,k,mid))lo=mid;else hi=mid;}return lo;}public static void main(String[] a)throws Exception{String text=new String(System.in.readAllBytes()).trim();if(text.isEmpty())return;String[] d=text.split("\\s+");int idx=0,t=Integer.parseInt(d[idx++]);StringBuilder out=new StringBuilder();for(int tc=0;tc<t;tc++){int n=Integer.parseInt(d[idx++]),k=Integer.parseInt(d[idx++]);int[] nums=new int[n];for(int i=0;i<n;i++)nums[i]=Integer.parseInt(d[idx++]);if(tc>0)out.append("\n\n");out.append(String.format(java.util.Locale.US,"%.5f",solve(nums,k)));}System.out.print(out);}}
